import SwiftUI
import UIKit

private enum EmbeddedImageData {
    static let logoBase64 = ""
    static let bikeBase64 = ""

    static func image(from base64: String) -> UIImage? {
        guard let data = Data(base64Encoded: base64) else { return nil }
        return UIImage(data: data)
    }
}

struct AptumLogoImage: View {
    var body: some View {
        Group {
            if let uiImage = EmbeddedImageData.image(from: EmbeddedImageData.logoBase64) {
                Image(uiImage: uiImage)
                    .resizable()
                    .scaledToFit()
            } else {
                ZStack {
                    RoundedRectangle(cornerRadius: 24)
                        .fill(.black.opacity(0.5))
                    Image(systemName: "triangle.fill")
                        .font(.largeTitle)
                        .foregroundStyle(.cyan)
                }
            }
        }
    }
}

struct AptumBikeImage: View {
    var body: some View {
        Group {
            if let uiImage = EmbeddedImageData.image(from: EmbeddedImageData.bikeBase64) {
                Image(uiImage: uiImage)
                    .resizable()
                    .scaledToFit()
            } else {
                ZStack {
                    RoundedRectangle(cornerRadius: 24)
                        .fill(.black.opacity(0.5))
                    Image(systemName: "motorcycle.fill")
                        .font(.largeTitle)
                        .foregroundStyle(.cyan)
                }
            }
        }
    }
}
